insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('ab118257-cbe5-5b47-bf43-2b47153184ae','00000000-0000-0000-0000-00000000a006','cosmo-central','Masteri Cosmo Central','project','NEXUS ZONE · CT3–CT4','[{"key":"Chủ đầu tư","value":"Masterise Homes®"},{"key":"Vị trí","value":"Lõi The Global City, Đỗ Xuân Hợp, P. Bình Trưng"},{"key":"Quy mô","value":"6 tháp 19–29 tầng + 3 khối đế + 2 hầm"},{"key":"Loại hình","value":"Căn hộ + Office + TMDV"},{"key":"Sản phẩm","value":"1PN → 4PN, Penthouse, Duplex"},{"key":"Sở hữu","value":"Lâu dài (khách quốc tịch VN)"},{"key":"Ra mắt","value":"15/01/2026"},{"key":"Bàn giao dự kiến","value":"Q3/2028"}]'::jsonb,'"Cosmo Central không bán một căn hộ — nó bán vị trí trái tim của khu đô thị duy nhất tại TP.HCM do Foster + Partners quy hoạch, ngay thời điểm hạ tầng khu Đông về đích đồng loạt."','Masteri Cosmo Central là phân khu cao tầng mới nhất trong lõi The Global City — nằm tại CT3 + CT4 ngay trục Đỗ Xuân Hợp, được định vị là "trái tim" của khu đô thị. Gồm 6 tháp 19–29 tầng, 3 tầng khối đế thương mại và 2 tầng hầm kết nối. Sản phẩm chính cho phân khúc căn hộ cao cấp: 1PN/1PN+/2PN/2PN+/3PN/4PN, Penthouse, Duplex. Mặt bằng B1 (tầng 5–15) ~19 căn/sàn; B2 (tầng 12B–17) ~12 căn/sàn, view kênh đào nhạc nước và SOHO. Đây là dự án Masterise đầu tiên mở bán ngay vào "thời điểm vàng" hạ tầng khu Đông hội tụ 2026–2027, với lịch bàn giao Q3/2028 rơi đúng vào giai đoạn định giá lại của toàn khu vực.',0),
  ('e6f4d1de-9eff-5fd4-8006-5ce6c392b885','00000000-0000-0000-0000-00000000a006','nexus-zone','Phân khu Nexus Zone','project','Giao điểm của mọi kết nối','[{"key":"Định vị","value":"Giao điểm của mọi kết nối"},{"key":"Slogan","value":"Sống trọn vẹn từng nhịp cộng hưởng"},{"key":"Vị trí cụm","value":"CT3–CT4 (Work-life Synergy)"}]'::jsonb,'"Nexus = điểm hội tụ. Khách của Nexus Zone là người muốn sống ngay giao điểm: vừa cạnh chỗ làm, vừa cạnh kênh nhạc nước, vừa cạnh trung tâm thương mại."','Nexus Zone là tên phân khu mở bán của Masteri Cosmo Central — định vị "Giao điểm của mọi kết nối", hướng đến giới chuyên gia, doanh nhân, công dân toàn cầu đề cao cân bằng công việc – cuộc sống. Liền kề khu Office và trục thương mại, 2 bên là kênh đào nhạc nước. Đây là "thấu kính cộng hưởng" của phong cách sống thế hệ mới: con người – không gian – trải nghiệm.',1),
  ('25d7515c-d8d0-5a8e-9460-d12e28db1347','00000000-0000-0000-0000-00000000a006','terra-tropical','Thiết kế Terra Tropical','project','Ngôn ngữ kiến trúc','[{"key":"Phong cách","value":"Nhiệt đới hiện đại, xếp lớp chuyển động"},{"key":"Đặc trưng","value":"Ban công rộng, kính toàn cảnh kịch trần"},{"key":"Triết lý","value":"Kết nối liền mạch trong – ngoài"}]'::jsonb,'"Terra Tropical không phải kiểu hộp kính lạnh lẽo — nó là kiến trúc thở được, đón gió đón sáng, đúng tinh thần sống nhiệt đới nhưng chuẩn quốc tế."','Terra Tropical là ngôn ngữ thiết kế riêng của Cosmo Central — nhịp điệu đô thị gặp tinh thần nhiệt đới hiện đại. Kiến trúc xếp lớp nhiều tầng chuyển động, ban công rộng mở, hệ cửa kính toàn cảnh phóng tầm ra đại cảnh đô thị. Cộng hưởng giữa chuẩn sống Masteri Collection và hệ tiện ích quốc tế The Global City tạo nên không gian đa sắc.',2),
  ('5a098ea5-5037-59e7-8581-133ec4abdd4e','00000000-0000-0000-0000-00000000a006','amenities','29+ Tiện ích đặc quyền','project','23 ngoài trời + 6 trong nhà','[{"key":"Tổng","value":"23 tiện ích ngoài trời + 6 trong nhà"},{"key":"Hồ bơi","value":"Vô cực + Jacuzzi + hồ trẻ em + nước nóng"},{"key":"Làm việc","value":"Business lounge, Co-working, thư viện"},{"key":"Sức khoẻ","value":"Gym, Yoga, sàn tắm nắng"},{"key":"Gia đình","value":"Kid playground, Teen club, BBQ"}]'::jsonb,'"Cư dân có cả không gian làm việc (Business Lounge, Co-working) lẫn nghỉ ngơi (hồ vô cực, yoga, teen club) trong cùng một khối đế — đúng tinh thần work-life synergy của CT3–CT4."','Hệ tiện ích 23 ngoài trời + 6 trong nhà (một số tài liệu cộng gộp tiện ích The Global City thành "50+"). Nổi bật: hồ bơi vô cực + jacuzzi + hồ nước nóng, sảnh cư dân 5 sao mỗi tháp, Business Lounge, Co-working Space, thư viện, phòng Gym, phòng Yoga, Kid Playground, Teen Club, chòi BBQ, bến kayak trên kênh.',3),
  ('0a05e557-daa5-5014-9ffb-8d14ae3ee4a5','00000000-0000-0000-0000-00000000a006','sales-policy','Chính sách khảo sát','project','Dự kiến — theo từng đợt CĐT','[{"key":"Đặt trước","value":"100 triệu/căn"},{"key":"Early Bird KH thường","value":"-1% (đến hết 31/05/2026)"},{"key":"Cư dân Masterise","value":"-2%"},{"key":"Hỗ trợ phí QL","value":"24 tháng"},{"key":"Vay HTLS","value":"70%, lãi suất 0% đến 31/10/2028"},{"key":"Chiết khấu TT sớm","value":"lên đến -11%"}]'::jsonb,'"Booking chỉ 100 triệu, early bird đến 31/5, cư dân Masterise thêm 2%, vay 0% lãi tới cuối 2028 — đòn bẩy này giúp khách giữ dòng tiền trong suốt giai đoạn hạ tầng về đích."','Chính sách khảo sát dự kiến (áp dụng theo từng thời điểm ban hành của CĐT). Đặt trước 100 triệu; Early Bird -1% (KH thường) / -2% (cư dân Masterise) đến hết 31/05/2026; hỗ trợ phí quản lý 24 tháng kể từ thông báo bàn giao. Các luồng thanh toán: theo tiến độ (HT -7%), thanh toán sớm (-9% đến -11%), vay vốn HTLS 70% lãi 0% đến 31/10/2028 (tối đa 6 tháng sau đủ điều kiện bàn giao).',4),
  ('96a36515-accc-5a3d-ab8c-10295f8a134e','00000000-0000-0000-0000-00000000a006','view-360','◉ Xem phối cảnh 360°','project','Mở tab mới','[{"key":"Loại","value":"Tương tác 360° tổng thể"},{"key":"Nguồn","value":"masterisehomes.com"}]'::jsonb,'"Cho khách xoay 360° ngay trên màn hình — họ thấy được vị trí trái tim của Cosmo Central giữa toàn cảnh kênh nhạc nước và SOHO trước khi tới nhà mẫu."','Trải nghiệm phối cảnh tổng thể The Global City dạng 360° tương tác — xoay toàn cảnh dự án, kênh đào nhạc nước, các phân khu và vị trí Masteri Cosmo Central. Nhấn nút bên dưới để mở trong tab mới.',5),
  ('a7f489a9-22cb-5766-a5b2-c9056e48579c','00000000-0000-0000-0000-00000000a006','masterise-group','Masterise Group','group',null,'[{"key":"Thành lập","value":"2007 (tiền thân Thảo Điền Investment)"},{"key":"Đổi tên","value":"2019 → Masterise Group"},{"key":"Vốn điều lệ","value":"VND 6,727 tỷ → 35,200 tỷ (8/2025)"},{"key":"Chủ tịch","value":"Hồ Anh Minh (sinh 1995, từ 13/1/2025)"},{"key":"Mảng","value":"BĐS · Vận hành · Hospitality · Hạ tầng"}]'::jsonb,'"Vốn điều lệ Masterise tăng gấp hơn 5 lần lên 35.200 tỷ chỉ trong một năm — đó là tín hiệu của một tập đoàn đang chuyển mình từ nhà phát triển BĐS thành nhà kiến tạo hạ tầng quốc gia."','Masterise Group (tiền thân CTCP Đầu tư Thảo Điền, 2007; đổi tên 2019) là tập đoàn tư nhân đa ngành. Vốn điều lệ được nâng từ VND 6,727 tỷ lên hơn 35,200 tỷ (8/2025) để phục vụ bước chuyển sang hạ tầng quốc gia. Hệ sinh thái: Masterise Homes (phát triển BĐS hàng hiệu), Masterise Property Management (vận hành), Masterise Hospitality & Entertainment (TTTM, sự kiện), Masterise Agents (phân phối), và các pháp nhân hạ tầng mới (hàng không, cầu).',6),
  ('882a47f5-3631-55b8-9b0c-4dd6539132d8','00000000-0000-0000-0000-00000000a006','ho-hung-anh','Hệ sinh thái Techcombank','group','Bên liên quan','[{"key":"Liên quan","value":"Gia đình Chủ tịch Techcombank Hồ Hùng Anh"},{"key":"Sở hữu","value":"Vợ + con trai Hồ Anh Minh > 10% mỗi người"},{"key":"Phó CT","value":"Hồ Anh Ngọc"}]'::jsonb,'"Đứng sau Masterise là hệ sinh thái Techcombank — một trong những ngân hàng tư nhân lớn nhất Việt Nam. Năng lực tài chính này là bảo chứng cho tiến độ dự án."','Theo Tuổi Trẻ (14/3/2025), Masterise Group là bên có liên quan đến Techcombank, do gia đình Chủ tịch Techcombank Hồ Hùng Anh chi phối: vợ (bà Nguyễn Thị Thanh Thủy) và con trai Hồ Anh Minh (sinh 1995) mỗi người sở hữu trên 10%; em trai Hồ Anh Ngọc là Phó Chủ tịch. Mối liên hệ này mang lại nền tảng tài chính và quản trị vững — yếu tố quan trọng cho cam kết bàn giao đúng hẹn.',7),
  ('5efd62f3-2209-50ad-baac-f29bd057fc34','00000000-0000-0000-0000-00000000a006','masterise-pm','Masterise Property Mgmt','group','Vận hành chuẩn quốc tế','[{"key":"Vai trò","value":"Vận hành & quản lý BĐS"},{"key":"Áp dụng","value":"The Global City + Cosmo Central"}]'::jsonb,'"Cùng một đơn vị vận hành đẳng cấp đang quản lý Grand Marina sẽ vận hành Cosmo Central — chuẩn dịch vụ không đổi."','Masterise Property Management vận hành và quản lý The Global City cũng như Masteri Cosmo Central theo tiêu chuẩn quốc tế — yếu tố giữ giá trị tài sản và chất lượng sống dài hạn.',8),
  ('379ba9ad-fda6-5063-84b3-5b090650faa3','00000000-0000-0000-0000-00000000a006','masterise-he','Masterise Hospitality & Ent.','group','TTTM · Sự kiện','[{"key":"Vai trò","value":"TTTM, F&B, sự kiện tại The Global City"}]'::jsonb,'"Chính đội ngũ này tạo ra ATVCG, SOOBIN, Global Wishmas — biến The Global City thành nơi cả Sài Gòn đổ về, kéo theo giá trị cho cư dân."','Mảng Hospitality & Entertainment vận hành trung tâm thương mại, F&B và chuỗi sự kiện quy mô lớn tại The Global City — biến khu đô thị thành điểm đến sống động (concert, lễ hội, thể thao).',9),
  ('71536758-a0c3-5c7c-b748-ca4af52b3b74','00000000-0000-0000-0000-00000000a006','cau-phu-my-2','Cầu Phú Mỹ 2','group','Masterise đầu tư · TP.HCM–Đồng Nai','[{"key":"Tổng đầu tư","value":"~VND 23,186 tỷ"},{"key":"Quy mô","value":"8 làn, 6.3 km, dây văng 2 tầng đầu tiên TP.HCM"},{"key":"Tĩnh không","value":"55m (cao nhất nhóm)"},{"key":"Khởi công","value":"15/01/2026"},{"key":"Kết nối","value":"Nguyễn Hữu Thọ → Đường liên cảng Đồng Nai"}]'::jsonb,'"Masterise tự bỏ vốn xây cây cầu 23.000 tỷ kết nối TP.HCM – Đồng Nai. Một chủ đầu tư có thể làm hạ tầng quốc gia thì chuyện bàn giao đúng hẹn một dự án căn hộ là điều đương nhiên."','Cầu Phú Mỹ 2 (~VND 23,186 tỷ, PPP) — cầu dây văng 2 tầng đầu tiên tại TP.HCM, 8 làn, 6.3 km, tĩnh không 55m. Khởi công 15/01/2026. Tạo trục nhanh Phú Mỹ Hưng → sân bay Long Thành. Đây là minh chứng cho năng lực hạ tầng của Masterise — không chỉ xây nhà mà xây cả huyết mạch giao thông quốc gia.',10),
  ('e41c9ed7-ed76-59cc-9a09-96b77b269183','00000000-0000-0000-0000-00000000a006','cau-can-gio','Cầu Cần Giờ','group','Masterise nghiên cứu đầu tư','[{"key":"Tổng đầu tư","value":"~VND 13,200 tỷ"},{"key":"Quy mô","value":"6 làn, dây văng vượt sông Soài Rạp"},{"key":"Khởi công","value":"15/01/2026 (chính thức 3/6/2026)"},{"key":"Hoàn thành","value":"30/6/2029"},{"key":"Thay thế","value":"Phà Bình Khánh"}]'::jsonb,'"Phú Mỹ 2, Cần Giờ, Gia Bình — ba dự án hạ tầng cùng một nhà đầu tư. Đó là tầm vóc của tập đoàn đứng sau Cosmo Central."','Cầu Cần Giờ (~VND 13,200 tỷ, PPP) — phá thế độc đạo phà Bình Khánh, rút Nhà Bè – Cần Giờ từ 2 giờ xuống 40–50 phút. Khởi công 15/01/2026, hoàn thành 30/6/2029. Kiến trúc dây văng lấy cảm hứng cây đước.',11),
  ('faa80c96-4365-59a1-9897-d1dc5a7e98c4','00000000-0000-0000-0000-00000000a006','gia-binh-airport','Sân bay QT Gia Bình','group','Masterise đầu tư · Bắc Ninh','[{"key":"Tổng đầu tư","value":"~VND 196,378 tỷ"},{"key":"Quy mô","value":"~1,960 ha, ICAO 4F, 2 đường băng 3,500m"},{"key":"Công suất 2030","value":"30 triệu khách + 1.6 triệu tấn"},{"key":"Công suất 2050","value":"50 triệu khách + 2.5 triệu tấn"},{"key":"Phê duyệt","value":"Quốc hội — NQ 256/2025/QH15 (11/12/2025)"},{"key":"Pháp nhân","value":"CTCP Hạ tầng HK Masterise (80%)"}]'::jsonb,'"Quốc hội giao Masterise đầu tư siêu sân bay 196.000 tỷ. Đây là cấp độ tín nhiệm cao nhất một doanh nghiệp tư nhân có thể đạt được tại Việt Nam."','Cảng hàng không quốc tế Gia Bình (Bắc Ninh) — tổng đầu tư ~VND 196,378 tỷ, được Quốc hội thông qua chủ trương cho Masterise đầu tư ngày 11/12/2025 (NQ 256/2025/QH15). Công suất 30 triệu khách (2030) → 50 triệu (2050), chuẩn ICAO 4F, mục tiêu 5 sao Skytrax top-10 thế giới.',12),
  ('b3118f66-71cd-5a63-9105-5a97cdbf493c','00000000-0000-0000-0000-00000000a006','masterise-homes','Masterise Homes','brand','11 năm · 27+ dự án','[{"key":"Khởi đầu","value":"2014 — Masteri Thảo Điền"},{"key":"Quy mô","value":"27+ dự án đẳng cấp quốc tế"},{"key":"Phạm vi","value":"HCM · Hà Nội · Hải Phòng · Đà Nẵng"},{"key":"3 phân khúc","value":"Branded Residences · LUMIÈRE · Masteri Collection"}]'::jsonb,'"11 năm, 27+ dự án, từ Masteri Thảo Điền đến Grand Marina. Cosmo Central kế thừa toàn bộ kinh nghiệm đó."','Masterise Homes® — nhà phát triển BĐS hàng hiệu tiên phong đưa chuẩn sống quốc tế về Việt Nam, hợp tác Marriott, Ritz-Carlton, JW Marriott, Elie Saab, Foster + Partners, WATG. Hành trình 11 năm từ Masteri Thảo Điền (2014) đến Masteri Cosmo Central (2026), dẫn dắt thị trường với 3 phân khúc: Branded Residences, LUMIÈRE Series, Masteri Collection.',13),
  ('d789b26b-cd06-5620-a387-ba98aa3c4107','00000000-0000-0000-0000-00000000a006','masteri-collection','Masteri Collection','brand','15 dự án · ~27,200 căn','[{"key":"Số dự án","value":"15"},{"key":"Số căn","value":"~27,200"},{"key":"Triết lý","value":"Đô thị vị nhân sinh"},{"key":"Cosmo Central","value":"thuộc dòng này"}]'::jsonb,'"Masteri Collection = chuẩn sống quốc tế cho công dân toàn cầu. Cosmo Central là phiên bản mới nhất, đặt ngay trái tim The Global City."','Masteri Collection là dòng sản phẩm cao cấp cốt lõi của Masterise Homes (15 dự án, ~27,200 căn) — mang triết lý "Đô thị vị nhân sinh", lấy con người làm trung tâm. Masteri Cosmo Central thuộc dòng này, thiết kế cho công dân toàn cầu hướng đến tiêu chuẩn sống quốc tế: kết nối toàn diện công việc – giáo dục – y tế – giải trí.',14),
  ('bd8209bb-d2d6-50f3-92a0-0dce42a1b578','00000000-0000-0000-0000-00000000a006','lumiere-series','LUMIÈRE Series','brand','8 dự án · ~14,500 căn','[{"key":"Số dự án","value":"8"},{"key":"Số căn","value":"~14,500"},{"key":"Tại TGC","value":"LUMIÈRE Midtown"}]'::jsonb,'"LUMIÈRE và Masteri Collection cùng tồn tại trong The Global City — cư dân Cosmo Central sống cạnh cả một hệ thương hiệu Masterise."','LUMIÈRE Series (8 dự án, ~14,500 căn) — dòng căn hộ cao cấp biểu tượng sống tinh anh. Tại The Global City có LUMIÈRE Midtown.',15),
  ('22567a09-5af3-57d0-be5a-2123df44d8be','00000000-0000-0000-0000-00000000a006','branded-residences','Branded Residences','brand','3 dự án · ~14,500 căn','[{"key":"Số dự án","value":"3"},{"key":"Gồm","value":"Grand Marina · The Grand Hanoi · The Rivus"}]'::jsonb,'"Một chủ đầu tư làm được căn hộ hàng hiệu Marriott, Ritz-Carlton, Elie Saab thì chuẩn hoàn thiện ở Cosmo Central nằm trong cùng một hệ DNA."','Phân khúc BĐS hàng hiệu quốc tế (3 dự án) đặt Masterise vào nhóm hiếm hoi toàn cầu: Grand Marina Saigon (Marriott & JW Marriott lớn nhất thế giới), The Grand Hanoi (Ritz-Carlton thứ 5 châu Á – TBD), The Rivus (121 dinh thự Elie Saab duy nhất VN).',16),
  ('bbff31a8-7c0d-53b3-ab6a-4213c9e382af','00000000-0000-0000-0000-00000000a006','masteri-thao-dien','Masteri Thảo Điền','brand','Chứng cứ tăng giá · 2014','[{"key":"Mở bán","value":"2014 @ ~35 triệu/m²"},{"key":"Hiện tại","value":"~100–131 triệu/m² (2025–26)"},{"key":"Tăng","value":"~3–4× trong một thập kỷ"},{"key":"Động lực","value":"Metro số 1 vận hành"}]'::jsonb,'"Masteri Thảo Điền 35 triệu năm 2014, nay hơn 100 triệu/m². Đó là track record tăng giá thực của thương hiệu Masteri ngay tại TP.HCM."','Masteri Thảo Điền — dự án đưa tên tuổi Masterise lên bản đồ. Mở bán 2014 ở mức ~35 triệu/m², thứ cấp 2025–26 đạt ~100–131 triệu/m² (Nhà Tốt) — tăng ~3–4 lần một thập kỷ, cộng hưởng Metro số 1.',17),
  ('ad546e1b-2f82-59ca-984b-75d5515e124f','00000000-0000-0000-0000-00000000a006','grand-marina','Grand Marina Saigon','brand','Marriott & JW Marriott · Q1','[{"key":"Vị trí","value":"Ba Son, Quận 1 — 10 ha"},{"key":"Thương hiệu","value":"Marriott & JW Marriott lớn nhất thế giới"},{"key":"Mốc","value":"Marriott Lake tower khai trương 14/11/2023"}]'::jsonb,'"Grand Marina là đỉnh tháp thương hiệu Masterise. Cosmo Central thừa hưởng cùng tiêu chuẩn thi công và vận hành."','Grand Marina Saigon — khu căn hộ hàng hiệu Marriott & JW Marriott lớn nhất thế giới, 10 ha tại Ba Son Q1. JW Marriott Residences Sea tower (2/2025) là khu hàng hiệu JW Marriott đô thị đầu tiên châu Á – TBD.',18),
  ('e7c905de-8605-573d-b8b5-9d078849ba0c','00000000-0000-0000-0000-00000000a006','the-grand-hanoi','The Grand Hanoi','brand','Ritz-Carlton Residences','[{"key":"Vị trí","value":"22–24 Hàng Bài, Hà Nội"},{"key":"Thương hiệu","value":"Ritz-Carlton thứ 5 châu Á – TBD"}]'::jsonb,null,'The Grand Hanoi — The Ritz-Carlton Residences thứ 5 tại châu Á – Thái Bình Dương, vị trí kim cương Hàng Bài, khai trương 5/2024.',19),
  ('ed4b6564-c77d-596f-9e07-512d3dba7416','00000000-0000-0000-0000-00000000a006','the-rivus','The Rivus by Elie Saab','brand','121 dinh thự Elie Saab','[{"key":"Quy mô","value":"121 dinh thự — duy nhất VN"},{"key":"Thương hiệu","value":"Elie Saab (Haute Couture)"},{"key":"Giải","value":"Best Residential Design in Asia 2025 (AADA)"}]'::jsonb,null,'The Rivus — 121 dinh thự hàng hiệu Elie Saab độc nhất Việt Nam (chỉ ~500 căn toàn cầu), trong Vinhomes Grand Park. Đạt giải "Best Residential Design in Asia 2025".',20),
  ('15cd78db-de64-5b19-a2bd-a2e0b9b245bb','00000000-0000-0000-0000-00000000a006','foster-partners','Foster + Partners','partner','Quy hoạch tổng thể TGC','[{"key":"Vai trò","value":"Cố vấn kiến trúc & quy hoạch tổng thể TGC"},{"key":"Ký kết","value":"22/02/2022, London"},{"key":"Công trình","value":"Apple HQ · Sân bay Hong Kong · Bloomberg HQ"},{"key":"Sáng lập","value":"Norman Foster (Pritzker Prize)"}]'::jsonb,'"The Global City là khu đô thị DUY NHẤT tại TP.HCM do Foster + Partners — studio thiết kế Apple Park và sân bay Hong Kong — quy hoạch. Không có đối thủ nào có pedigree này."','Foster + Partners — studio kiến trúc huyền thoại đứng sau Apple Park, sân bay quốc tế Hong Kong, Bloomberg HQ London, tòa Gherkin, sân Wembley, Lusail Stadium. Norman Foster đoạt giải Pritzker. F+P được bổ nhiệm làm cố vấn kiến trúc & quy hoạch tổng thể The Global City (22/02/2022) — township đầu tiên của F+P tại Việt Nam, đồng thời định hướng kiến trúc Cosmo Central.',21),
  ('c0ef2956-cace-5e18-af36-de97977e9469','00000000-0000-0000-0000-00000000a006','watg','WATG','partner','Cảnh quan TGC','[{"key":"Vai trò","value":"Quy hoạch cảnh quan TGC"},{"key":"Vị thế","value":"Top 3 hãng thiết kế hospitality thế giới"}]'::jsonb,'"450.000 m² cây xanh và mặt nước được quy hoạch bởi WATG — triết lý đối thoại với thiên nhiên ngay giữa lõi đô thị."','WATG — một trong những hãng thiết kế hospitality lớn nhất thế giới (top 3 BD+C Giants 400 2025), phụ trách cảnh quan The Global City: bố trí không gian, ánh sáng, gió, 450.000 m² cây xanh & mặt nước.',22),
  ('54485e33-e6fa-5955-bfa6-c291d9d53581','00000000-0000-0000-0000-00000000a006','marriott','Marriott International','partner',null,'[{"key":"Hợp tác","value":"Grand Marina (Marriott, JW Marriott)"}]'::jsonb,null,'Tập đoàn khách sạn hàng đầu thế giới — đối tác thương hiệu của Masterise tại Grand Marina Saigon (Marriott & JW Marriott Residences).',23),
  ('c7f367e6-2f45-56a3-a4ed-db758c1e5e6c','00000000-0000-0000-0000-00000000a006','ritz-carlton','The Ritz-Carlton','partner',null,'[{"key":"Hợp tác","value":"The Grand Hanoi"}]'::jsonb,null,'Thương hiệu khách sạn siêu sang — The Ritz-Carlton Residences tại The Grand Hanoi (thứ 5 châu Á – TBD).',24),
  ('6ed156ea-d2f5-5dee-89c1-92a70039f163','00000000-0000-0000-0000-00000000a006','elie-saab','Elie Saab','partner',null,'[{"key":"Hợp tác","value":"The Rivus — 121 dinh thự"}]'::jsonb,null,'Nhà mốt Haute Couture Lebanon — lần đầu thiết kế dinh thự hàng hiệu tại Việt Nam qua The Rivus.',25),
  ('d3220ba5-7f03-5271-ac23-16969b080b07','00000000-0000-0000-0000-00000000a006','the-global-city','The Global City','masterplan','117.4 ha · Foster + Partners','[{"key":"Quy mô","value":"117.4 ha"},{"key":"Chủ đầu tư","value":"Masterise Homes"},{"key":"Quy hoạch","value":"Foster + Partners (22/02/2022)"},{"key":"Cảnh quan","value":"WATG — 450,000 m² xanh & mặt nước"},{"key":"Vị trí","value":"Đỗ Xuân Hợp, P. Bình Trưng, TP.HCM"},{"key":"Định vị","value":"Biểu tượng trung tâm chuẩn sống toàn cầu"}]'::jsonb,'"The Global City không phải dự án — là một thành phố thu nhỏ chuẩn quốc tế 117 ha. Cosmo Central nằm ngay trái tim của thành phố đó."','The Global City — khu đô thị phức hợp 117.4 ha do Masterise Homes phát triển, là khu đô thị duy nhất tại TP.HCM được Foster + Partners quy hoạch tổng thể. Mô hình all-in-one quốc tế: TTTM 123,000 m², 6 trường quốc tế, 1 bệnh viện quốc tế, kênh đào nhạc nước lớn nhất Đông Nam Á (2km), SOHO, City Park, Speedway. Định vị "Biểu tượng trung tâm chuẩn sống toàn cầu" — New Downtown phía Đông, giữa Thủ Thiêm IFC và sân bay Long Thành.',26),
  ('fca6ecd9-5453-5254-b0cc-cd9bb2421d13','00000000-0000-0000-0000-00000000a006','canal-of-love','Kênh đào nhạc nước','masterplan','Lớn nhất Đông Nam Á · 2km','[{"key":"Chiều dài","value":"~2 km"},{"key":"Vị thế","value":"Kênh nhạc nước al-fresco lớn nhất ĐNÁ"}]'::jsonb,'"Căn hộ view kênh nhạc nước lớn nhất Đông Nam Á — đây là loại view không thể sao chép ở bất kỳ dự án nào khác TP.HCM."','Kênh đào nhạc nước dài hơn 2km — lớn nhất Đông Nam Á, chạy xuyên The Global City. Cosmo Central có view trực tiếp ra kênh, với bến kayak nội khu.',27),
  ('32636c4e-7017-5ed9-8a3e-58241a3b03a3','00000000-0000-0000-0000-00000000a006','tttm-mall','TTTM 123,000 m²','masterplan','Grade-A shopping mall','[{"key":"Quy mô","value":"~123,000 m² (một số tài liệu 125,000)"},{"key":"Hạng","value":"Grade-A, thuộc nhóm lớn nhất VN"}]'::jsonb,null,'Trung tâm thương mại Grade-A ~123,000 m² — thuộc nhóm lớn nhất Việt Nam, đi bộ 5 phút từ Cosmo Central.',28),
  ('e5852e72-7a6f-56dd-a2ef-5ef900fa3091','00000000-0000-0000-0000-00000000a006','soho-district','Khu SOHO','masterplan','Phố thương mại sôi động','[{"key":"Loại","value":"Shophouse thấp tầng"},{"key":"Vị trí","value":"Liền kề Cosmo Central"}]'::jsonb,null,'Khu phố thương mại SOHO — shophouse thấp tầng sôi động, đi bộ 1 phút từ Cosmo Central, tạo nhịp sống thương mại ngay dưới chân tháp.',29),
  ('aede14ad-6087-56c9-9f53-baa74d1cae80','00000000-0000-0000-0000-00000000a006','tgc-school-hospital','6 trường QT + BV QT','masterplan','All-in-one','[{"key":"Giáo dục","value":"6 trường tiêu chuẩn quốc tế"},{"key":"Y tế","value":"1 bệnh viện tiêu chuẩn quốc tế"}]'::jsonb,'"Trường quốc tế và bệnh viện quốc tế ngay trong khu đô thị — con đi học, ông bà khám bệnh đều trong bán kính đi bộ. Đó là all-in-one thật sự."','The Global City quy hoạch 6 trường học quốc tế + 1 bệnh viện quốc tế nội khu — đáp ứng nhu cầu giáo dục, y tế trong bán kính đi bộ, đúng tiêu chí top khách hàng ưu tiên (giáo dục 33%, y tế 32%).',30),
  ('a1258df7-5adc-5c26-8b95-e19449c0d78b','00000000-0000-0000-0000-00000000a006','masteri-park-place','Masteri Park Place','cluster','CT5 · The Global City','[{"key":"Vị trí","value":"CT5, ôm 2 mặt nước"},{"key":"Định vị","value":"Giao điểm năng lượng"}]'::jsonb,null,'Phân khu cao tầng tại CT5 The Global City — "giao điểm năng lượng" ôm trọn 2 mặt nước. Cùng hệ sinh thái với Cosmo Central.',31),
  ('e1037914-1ce0-5576-aae8-3b61b603e99b','00000000-0000-0000-0000-00000000a006','masteri-grand-view','Masteri Grand View','cluster','Mặt tiền kim cương','[{"key":"Định vị","value":"Flexi-luxury, modernista"},{"key":"Giá tham khảo","value":"~120–130 triệu/m² (môi giới)"}]'::jsonb,null,'Phân khu cao tầng đầu tiên tại vị trí "kim cương" mặt tiền The Global City. Giá môi giới tham khảo ~120–130 triệu/m².',32),
  ('e09ba101-7d71-5b48-bfcf-d84b0136b9d8','00000000-0000-0000-0000-00000000a006','lumiere-midtown','LUMIÈRE Midtown','cluster','The Art of Living','[{"key":"Dòng","value":"LUMIÈRE Series tại TGC"},{"key":"Giá tham khảo","value":"~150–160 triệu/m² (môi giới)"}]'::jsonb,null,'Biểu tượng dòng LUMIÈRE tại The Global City — kiến trúc New York hiện đại. Giá môi giới tham khảo ~150–160 triệu/m².',33),
  ('c8d0354c-a0c6-5eae-985e-c788aa4a525a','00000000-0000-0000-0000-00000000a006','sola','SOLA Villas','cluster','Dinh thự biểu tượng','[{"key":"Loại","value":"Biệt thự/dinh thự"},{"key":"Giá đất tham khảo","value":"~380–570 triệu/m² (môi giới)"}]'::jsonb,null,'Dòng dinh thự biểu tượng tại The Global City. Giá đất môi giới tham khảo ~380–570 triệu/m² — cho thấy mặt bằng giá thấp tầng trong khu đã rất cao.',34),
  ('96c486f9-87a9-5b54-a990-84f5206a409f','00000000-0000-0000-0000-00000000a006','rach-chiec','KLH TDTT Rạch Chiếc','cluster','Sun Group · 186.78 ha','[{"key":"Quy mô","value":"186.78 ha"},{"key":"Vốn","value":"~VND 145,629 tỷ (~6 tỷ USD)"},{"key":"Sân vận động","value":"65,000–75,000 chỗ"},{"key":"Khởi công","value":"15/01/2026"},{"key":"Tầm nhìn","value":"2030 — biểu tượng quốc gia"}]'::jsonb,'"Cosmo Central nằm trong cụm đô thị – thể thao 368 ha duy nhất TP.HCM: The Global City + Saigon Sports City + Rạch Chiếc. Cư dân có cả sân vận động quốc gia trong tầm tay."','Khu liên hợp TDTT Quốc gia Rạch Chiếc (Sun Group) — 186.78 ha, ~VND 145,629 tỷ, sân vận động 65,000–75,000 chỗ, nhà thi đấu 18,000 chỗ, trung tâm thể thao dưới nước, bệnh viện thể thao. Khởi công 15/01/2026. Cùng Saigon Sports City (64 ha) và The Global City (117.4 ha) tạo thành cụm đô thị – thể thao ~368 ha duy nhất TP.HCM, kết nối trực tiếp qua đường Liên Phường.',35),
  ('1463d5e0-3a04-5441-a817-12655c62c7d3','00000000-0000-0000-0000-00000000a006','saigon-sports-city','Saigon Sports City','cluster','64 ha · cụm thể thao','[{"key":"Quy mô","value":"64 ha"},{"key":"Ghi chú","value":"Keppel đã bán 70% (2025), giữ 30%"}]'::jsonb,null,'Saigon Sports City 64 ha — mắt xích giữa Rạch Chiếc và The Global City trong cụm đô thị – thể thao 368 ha. Keppel đã chuyển nhượng 70% vốn (2025), giữ 30% làm căn hộ sau này.',36),
  ('b86c76db-5456-5748-8eec-281469b3f973','00000000-0000-0000-0000-00000000a006','atvcg','Concert ATVCG','event','Anh Trai Vượt Ngàn Chông Gai','[{"key":"Thời gian","value":"Chặng cuối 6–7/9/2025"},{"key":"Quy mô","value":"20.000 → hơn 50.000 người/đêm"}]'::jsonb,'"50.000 người đổ về The Global City trong một đêm concert. Đó là sức hút khu đô thị mà tiền không mua được — và cư dân Cosmo Central sống ngay tại đó."','Chuỗi concert "Anh Trai Vượt Ngàn Chông Gai" — chặng cuối 6–7/9/2025 tại The Global City, thu hút từ 20.000 lên hơn 50.000 người/đêm (Nhân Dân, VnExpress).',37),
  ('8ab78428-a7de-5312-b886-b85595dd9e98','00000000-0000-0000-0000-00000000a006','soobin-concert','SOOBIN Concert','event','29/11/2025 · sold-out','[{"key":"Thời gian","value":"29/11/2025"},{"key":"Tên","value":"All-Rounder The Final"}]'::jsonb,null,'Live Concert SOOBIN "All-Rounder The Final" — 29/11/2025 tại The Global City, cháy vé (Báo Xây Dựng).',38),
  ('1d902bc9-2008-5cf3-a109-aa7a98cd5a7d','00000000-0000-0000-0000-00000000a006','quoc-thien','Quốc Thiên SKYNote','event','22/11/2025 · ~10,000 người','[{"key":"Thời gian","value":"22/11/2025"},{"key":"Tên","value":"SKYNote 2025: The Reflection"}]'::jsonb,null,'Concert Quốc Thiên "SKYNote 2025" — 22/11/2025 tại The Global City, gần 10.000 khán giả (TTXVN/Thể thao Văn hóa).',39),
  ('d7a82721-0a3f-5bda-94bc-a0f7017de6be','00000000-0000-0000-0000-00000000a006','ppa-tour','PPA Tour Asia','event','MB Vietnam Open 2025','[{"key":"Môn","value":"Pickleball quốc tế"},{"key":"Địa điểm","value":"TGC Sports Complex / Arena"}]'::jsonb,null,'PPA Tour Asia — MB Vietnam Open 2025 diễn ra tại The Global City Sports Complex — giải pickleball chuyên nghiệp quốc tế, định vị khu đô thị trên bản đồ thể thao khu vực.',40),
  ('17ca43cb-1098-55ae-8793-86286c2643ea','00000000-0000-0000-0000-00000000a006','pink-run','Pink Run / Nón Hồng','event','25/10/2025 · 5,000+ runner','[{"key":"Thời gian","value":"25/10/2025"},{"key":"Quy mô","value":">5,000 runner"}]'::jsonb,null,'Vietnam Women Run / Ngày hội Nón Hồng — 25/10/2025 tại The Global City, hơn 5.000 vận động viên (Người Lao Động).',41),
  ('8ae11e78-e2be-5746-810c-fd8d76abe3c4','00000000-0000-0000-0000-00000000a006','global-wishmas','Global Wishmas 2025','event','12/2025 · lễ hội Giáng sinh','[{"key":"Thời gian","value":"20, 21, 24/12/2025"},{"key":"Loại","value":"Chợ Giáng sinh châu Âu + diễu hành"}]'::jsonb,null,'Global Wishmas 2025 — chợ Giáng sinh phong cách châu Âu, diễu hành Wishmas, dàn nhạc giao hưởng, thuộc chuỗi Global Festive (13/12/2025 – 10/1/2026).',42),
  ('d82dcb0c-6633-5928-80bc-2d4442b694ac','00000000-0000-0000-0000-00000000a006','daddy-cool','Daddy Cool Diner','event','Quán retro thường trực · City Park','[{"key":"Loại","value":"Diner retro Mỹ thập niên 90"},{"key":"Mở cửa","value":"Tết 2026 · ~1,000+ khách/ngày"}]'::jsonb,null,'Daddy Cool — diner phong cách Mỹ retro thập niên 90 thường trực tại City Park (mở Tết 2026), thu hút ~1.000+ khách/ngày. Điểm đến hằng ngày chứ không chỉ sự kiện.',43),
  ('e39eede8-8f14-53a1-9389-91752c72dee7','00000000-0000-0000-0000-00000000a006','lien-phuong','Đường Liên Phường','infra','Thông xe 8/11/2025','[{"key":"Chiều dài","value":"~6.7 km"},{"key":"Đoạn TGC","value":"1.6 km, lộ giới 60m, 6 làn"},{"key":"Kết nối","value":"Cát Lái – Mai Chí Thọ → Vành đai 3"},{"key":"Mốc","value":"Thông toàn tuyến kỹ thuật 8/11/2025"}]'::jsonb,'"Đường Liên Phường — chính Masterise tham gia làm — đã thông xe tháng 11/2025, đưa Thảo Điền về The Global City chỉ còn 5 phút. Hạ tầng không còn là lời hứa, nó đã chạy."','Đường Liên Phường (~6.7 km) nối Cát Lái – Mai Chí Thọ xuyên qua trái tim The Global City đến Vành đai 3. Đoạn kết nối TGC – Mai Chí Thọ dài 1.6 km, lộ giới 60m, 6 làn. Thông toàn tuyến kỹ thuật 8/11/2025 (cầu vượt rạch Mương Kinh). Rút Thảo Điền → TGC còn ~5 phút; Thủ Thiêm/Q1 → TGC ~10–15 phút; kết nối thẳng cụm thể thao Rạch Chiếc.',44),
  ('67454760-4a0f-5734-a133-2802d720d039','00000000-0000-0000-0000-00000000a006','nut-giao-an-phu','Nút giao An Phú','infra','Hoàn thành Q2/2026','[{"key":"Quy mô","value":"Nút giao 3 tầng — VND 3,408 tỷ"},{"key":"HC1-01","value":"Thông xe 30/6/2025"},{"key":"Cầu N2","value":"Thông xe 31/12/2025"},{"key":"HC1-02","value":"Thông xe 2/2/2026"},{"key":"Hoàn thành","value":"Q2/2026"}]'::jsonb,'"Khi nút giao An Phú hoàn thành Q2/2026, Cosmo Central kết nối thẳng cao tốc Long Thành và trung tâm Q1 — đúng lúc dự án vào giai đoạn tăng tốc thi công."','Nút giao An Phú — nút giao 3 tầng VND 3,408 tỷ, cửa ngõ biểu tượng mới phía Đông. HC1-01 (30/6/2025), cầu N2 (31/12/2025), HC1-02 (2/2/2026) đã thông; hoàn thành toàn bộ Q2/2026. Tổ hợp N2 + HC1-02 giảm ~80% ùn tắc tại nút.',45),
  ('848ed61e-802f-5ada-955a-ec40a9d99b76','00000000-0000-0000-0000-00000000a006','vanh-dai-2','Vành đai 2','infra','Lá chắn trục trung tâm · 2027','[{"key":"Đoạn 1+2+3","value":"Cầu Phú Hữu → Gò Dưa, ~9km"},{"key":"Khởi công","value":"19/12/2025"},{"key":"Hoàn thành","value":"2027"}]'::jsonb,'"Vành đai 2 khép kín 2027 đẩy xe tải ra khỏi trục trung tâm — chất lượng sống quanh Cosmo Central được nâng lên rõ rệt."','Vành đai 2 — đoạn 1+2+3 (cầu Phú Hữu → Võ Nguyên Giáp → Phạm Văn Đồng → Gò Dưa, ~9km) khởi công 19/12/2025, hoàn thành 2027. "Lá chắn trục trung tâm" — chuyển hướng xe lớn khỏi trục Đỗ Xuân Hợp / Mai Chí Thọ.',46),
  ('b2fa26a2-36bf-5d52-bbde-988aea043798','00000000-0000-0000-0000-00000000a006','vanh-dai-3','Vành đai 3','infra','Đòn bẩy kinh tế · 6/2026','[{"key":"Tổng","value":"76.34 km, ~VND 75,378 tỷ"},{"key":"Đoạn Đông 14.7km","value":"Thông kỹ thuật 19/12/2025"},{"key":"Toàn tuyến","value":"Vận hành 30/6/2026"},{"key":"Kết nối","value":"HCM · Đồng Nai · Tây Ninh · BR-VT"}]'::jsonb,'"Vành đai 3 vận hành 6/2026 — chỉ vài tháng trước khi Cosmo Central tăng tốc. Cả vùng Đông được tái định giá theo trục kinh tế mới này."','Vành đai 3 — 76.34 km, ~VND 75,378 tỷ. Đoạn Đông 14.7km cầu cạn qua Thủ Đức thông kỹ thuật 19/12/2025; toàn tuyến vận hành 30/6/2026. Đòn bẩy kinh tế liên vùng, kết nối cao tốc Long Thành.',47),
  ('c0009f40-a3e8-552a-bde6-0ff8282be270','00000000-0000-0000-0000-00000000a006','cao-toc-long-thanh','Mở rộng cao tốc Long Thành','infra','8–10 làn · 12/2026','[{"key":"Quy mô","value":"Mở rộng 8–10 làn xe"},{"key":"Khởi công","value":"19/8/2025"},{"key":"Hoàn thành","value":"Dec 2026 (đồng bộ sân bay Long Thành)"}]'::jsonb,'"Cao tốc mở rộng xong cuối 2026 — Cosmo Central tới sân bay Long Thành chỉ còn ~30 phút. Đó là khoảng cách của một đô thị sân bay đẳng cấp."','Mở rộng cao tốc TP.HCM – Long Thành – Dầu Giây lên 8–10 làn (VEC), khởi công 19/8/2025, cơ bản hoàn thành Dec 2026 — đồng bộ với sân bay Long Thành. Cầu Long Thành đơn nguyên mới hợp long 12/2026.',48),
  ('f62261d6-c8a6-5f84-b001-eead6bd67bc6','00000000-0000-0000-0000-00000000a006','metro-2-tham-luong','Metro 2 — Tham Lương','infra','Khởi công 15/01/2026','[{"key":"Tuyến","value":"Bến Thành – Tham Lương"},{"key":"Quy mô","value":"11.3 km, 11 ga, VND 55,179 tỷ"},{"key":"Vận hành","value":"Q4/2030"}]'::jsonb,null,'Metro số 2 (Bến Thành – Tham Lương) — 11.3 km, 11 ga, khởi công 15/01/2026, vận hành Q4/2030. Trục xương sống kết nối trung tâm.',49),
  ('971d28a8-1ca5-5004-9d22-58a140f4e26b','00000000-0000-0000-0000-00000000a006','metro-2-thu-thiem','Metro 2 — Thủ Thiêm','infra','Khởi công 29/4/2026','[{"key":"Tuyến","value":"Bến Thành – Thủ Thiêm"},{"key":"Quy mô","value":"6 km, 6 ga ngầm dưới sông Sài Gòn"},{"key":"Vận hành","value":"Q3/2030"}]'::jsonb,'"Trục Tham Lương – Bến Thành – Thủ Thiêm – Long Thành trở thành xương sống metro. Cosmo Central tiếp cận qua Ga Thủ Thiêm chỉ 10 phút đi đường Liên Phường."','Metro số 2 nhánh Bến Thành – Thủ Thiêm — 6 km, 6 ga ngầm (hầm metro đầu tiên xuyên đáy sông Sài Gòn), khởi công 29/4/2026, vận hành Q3/2030. Kết nối thẳng trục Long Thành.',50),
  ('091d9d33-19bf-5c39-9246-a84dcf5164e6','00000000-0000-0000-0000-00000000a006','thu-thiem-long-thanh-rail','ĐSĐT Thủ Thiêm – Long Thành','infra','Khởi công trước 30/6/2026','[{"key":"Chiều dài","value":"48 km, ~VND 84,000 tỷ"},{"key":"Kết nối","value":"Ga Thủ Thiêm → sân bay Long Thành 30 phút"},{"key":"Vận hành","value":"2030"}]'::jsonb,null,'Đường sắt đô thị Thủ Thiêm – Long Thành (48 km, ~VND 84,000 tỷ) — khởi công trước 30/6/2026, vận hành 2030. Kết nối The Global City (qua Ga Thủ Thiêm) đến sân bay Long Thành trong 30 phút.',51),
  ('cc48c271-5b68-55bd-98a0-db5084ffe518','00000000-0000-0000-0000-00000000a006','long-thanh-airport','Sân bay Long Thành','infra','Khai thác giữa 2026','[{"key":"Giai đoạn 1","value":"25 triệu khách/năm, ~US$16 tỷ"},{"key":"Bay thử Boeing 787","value":"15/12/2025"},{"key":"Chuyến TM đầu","value":"19/12/2025"},{"key":"Khai thác TM","value":"Giữa 2026"}]'::jsonb,'"Sân bay Long Thành khai thác giữa 2026 kéo theo hàng vạn chuyên gia về phía Đông. The Global City là điểm dừng chân chuẩn quốc tế gần nhất giữa Thủ Thiêm và Long Thành."','Sân bay quốc tế Long Thành — giai đoạn 1 đón 25 triệu khách/năm, ~US$16 tỷ. Bay thử Boeing 787 ngày 15/12/2025, 3 chuyến thương mại đầu 19/12/2025, khai thác thương mại giữa 2026.',52),
  ('f0e122ef-2006-5380-a617-cd45a8157665','00000000-0000-0000-0000-00000000a006','ifc-thu-thiem','Trung tâm Tài chính QT','finance','Công bố 21/12/2025','[{"key":"Công bố","value":"21/12/2025 (NĐ 323/2025/NĐ-CP)"},{"key":"Quy mô HCM","value":"~898 ha"},{"key":"Mô hình","value":"Một trung tâm – hai địa điểm"},{"key":"Lộ trình","value":"2026 hạ tầng → 2030 ASEAN → 2035 toàn cầu"}]'::jsonb,'"Trung tâm Tài chính Quốc tế đặt tại Thủ Thiêm — New Downtown của TP.HCM. Cosmo Central cách đó 10 phút, là điểm an cư cho chính các chuyên gia tài chính sẽ về đây."','Trung tâm Tài chính Quốc tế (IFC) — Thủ tướng công bố thành lập 21/12/2025. Cấu phần TP.HCM ~898 ha trải dài Phường Sài Gòn, Phường Bến Thành và Thủ Thiêm. Lộ trình: 2026 hạ tầng & thu hút đầu tư → 2027–2030 tầm vóc ASEAN (trụ sở dời về Thủ Thiêm) → 2035 tầm vóc toàn cầu. IFC sẽ kéo dòng vốn và chuyên gia nước ngoài về Thủ Thiêm — nhu cầu nhà ở cao cấp lân cận tăng mạnh. Cosmo Central cách Thủ Thiêm ~10 phút.',53),
  ('be8e927b-b5e2-5cf9-921d-cc99b0c98a04','00000000-0000-0000-0000-00000000a006','thu-thiem-cbd','Thủ Thiêm CBD','finance','New Downtown','[{"key":"Vai trò","value":"CBD tài chính mới"},{"key":"Giá biệt thự Sala","value":"900 triệu – 1.5 tỷ/m² (môi giới)"}]'::jsonb,'"Thủ Thiêm đã chạm ngưỡng tỷ đồng/m². Cosmo Central — cách 10 phút, giá căn hộ — đang ở vùng định giá hấp dẫn hơn nhiều so với mặt bằng CBD mới."','Thủ Thiêm — trung tâm tài chính mới của TP.HCM, nơi đặt lõi IFC. Giá biệt thự Sala đã đạt 900 triệu – 1.5 tỷ/m² (môi giới), tạo mặt bằng giá tham chiếu cho toàn khu Đông.',54),
  ('4a6791a9-3101-5527-b17d-d5f781a1e46f','00000000-0000-0000-0000-00000000a006','market-2026','Thị trường căn hộ 2026','finance','Savills / CBRE','[{"key":"Hấp thụ 2025","value":"82% — cao nhất 5 năm"},{"key":"Giá sơ cấp HCM","value":"~92–102 triệu/m²"},{"key":"Cao cấp >110tr/m²","value":"56% nguồn cung mới"},{"key":"Pipeline khu Đông","value":"~50% giai đoạn 2026–28"},{"key":"Dự báo giá","value":"+10–20%/năm"}]'::jsonb,'"Phân khúc bình dân đang biến mất khỏi trung tâm — quỹ đất cực hiếm. Mua căn hộ cao cấp khu Đông hôm nay là đón đầu mặt bằng giá mới tăng 10–20%/năm."','Theo Savills/CBRE: 2025 TP.HCM hấp thụ ~11.500 căn, tỷ lệ 82% (cao nhất 5 năm); giá sơ cấp ~92–102 triệu/m²; phân khúc >110 triệu/m² chiếm 56% nguồn cung mới; sản phẩm dưới 50 triệu/m² còn 12%. Pipeline 2026–28 ~58.000 căn, khu Đông chiếm ~50%. Dự báo giá sơ cấp +10–20%/năm.',55),
  ('2ccab86d-aff9-50bb-8c94-ffd5a4a27f36','00000000-0000-0000-0000-00000000a006','macro-vn','Vĩ mô Việt Nam 2025–26','finance','GSO','[{"key":"GDP Q1/2025","value":"+6.93% (cao nhất từ 2020)"},{"key":"FDI giải ngân 2025","value":"US$27.62 tỷ (+9%, cao nhất 5 năm)"},{"key":"GRDP HCM 2025","value":"+7.53%"},{"key":"Dòng tiền","value":"BĐS là kênh trú ẩn dài hạn"}]'::jsonb,'"Chứng khoán và vàng biến động, lãi suất hạ — dòng tiền tìm về BĐS chuẩn quốc tế. Đó là lý do căn hộ cao cấp khu Đông đang hút vốn mạnh nhất."','Theo Tổng cục Thống kê (GSO): GDP Q1/2025 +6.93% (cao nhất từ 2020); FDI giải ngân cả năm 2025 đạt US$27.62 tỷ (+9% YoY, cao nhất 5 năm); GRDP TP.HCM 2025 +7.53%. Lãi suất hạ nhiệt cuối 2025 đẩy dòng tiền về BĐS — kênh đầu tư phát triển bền vững, dài hạn.',56);
